import { Check } from "lucide-react"

const ROWS = [
  {
    kicker: "// runtime",
    title: "Compile intent, not code",
    body: "Describe the outcome; Nexen routes the daemons, allocates the cycles, and ships the trace. You stay in the flow.",
    points: ["Sub-ms compile", "Auto-allocated cycles", "Zero boilerplate"],
  },
  {
    kicker: "// defense",
    title: "Walk past the ICE",
    body: "Adaptive ICE-breakers learn the grid as you move. When the wall shifts, your route shifts with it.",
    points: ["Adaptive routing", "Live threat map", "Silent fallback"],
  },
]

/**
 * Cyber features — alternating rows with a neon checklist and a glowing panel.
 */
export function FeatureCyber() {
  return (
    <section className="border-b border-primary/20 bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-6xl space-y-6">
        {ROWS.map((r, i) => (
          <div
            key={r.title}
            className={`grid items-center gap-8 border border-border bg-card p-6 sm:p-8 md:grid-cols-2 ${
              i % 2 === 1 ? "md:[&>*:first-child]:order-2" : ""
            }`}
          >
            <div>
              <p className="font-mono text-[11px] tracking-[0.25em] uppercase text-accent">{r.kicker}</p>
              <h3 className="mt-3 text-3xl font-black tracking-tight">{r.title}</h3>
              <p className="mt-3 text-muted-foreground">{r.body}</p>
              <ul className="mt-5 space-y-2">
                {r.points.map((p) => (
                  <li key={p} className="flex items-center gap-2.5 font-mono text-sm tracking-wide">
                    <span className="grid size-5 place-items-center border border-primary/50 text-primary shadow-[0_0_8px_rgba(34,211,238,0.4)]">
                      <Check className="size-3" />
                    </span>
                    {p}
                  </li>
                ))}
              </ul>
            </div>
            <div className="relative grid min-h-[200px] place-items-center overflow-hidden border border-primary/30 bg-[linear-gradient(135deg,rgba(34,211,238,0.12),rgba(255,0,229,0.12))]">
              <div aria-hidden className="absolute inset-0 bg-[linear-gradient(rgba(34,211,238,0.12)_1px,transparent_1px)] bg-[size:100%_22px]" />
              <span className="relative font-mono text-5xl font-black text-primary/70">0{i + 1}</span>
            </div>
          </div>
        ))}
      </div>
    </section>
  )
}

"use client"

import { useRef } from "react"
import { motion, useScroll, useTransform } from "framer-motion"

/**
 * Cyber parallax — a neon statement over a perspective grid that drifts on scroll.
 */
export function ParallaxCyber() {
  const ref = useRef<HTMLDivElement>(null)
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start end", "end start"] })

  const grid = useTransform(scrollYProgress, [0, 1], ["0%", "30%"])
  const glow = useTransform(scrollYProgress, [0, 0.5, 1], [0.25, 0.6, 0.25])

  return (
    <section
      ref={ref}
      className="relative grid min-h-[460px] place-items-center overflow-hidden border-b border-primary/20 bg-background px-5 py-24 text-foreground"
    >
      <motion.div
        aria-hidden
        style={{ backgroundPositionY: grid }}
        className="pointer-events-none absolute inset-0 bg-[linear-gradient(rgba(34,211,238,0.12)_1px,transparent_1px),linear-gradient(90deg,rgba(34,211,238,0.12)_1px,transparent_1px)] bg-[size:50px_50px] [mask-image:linear-gradient(to_bottom,transparent,black,transparent)]"
      />
      <motion.div
        aria-hidden
        style={{ opacity: glow }}
        className="pointer-events-none absolute left-1/2 top-1/2 size-[55vw] max-w-[640px] -translate-x-1/2 -translate-y-1/2 rounded-full bg-[radial-gradient(circle,rgba(255,0,229,0.22),transparent_65%)]"
      />

      <div className="relative max-w-3xl text-center">
        <p className="font-mono text-[11px] tracking-[0.3em] uppercase text-primary">// nexen.manifest</p>
        <h2 className="mt-5 text-[clamp(2rem,7vw,4.75rem)] font-black leading-[0.95] tracking-tight">
          The grid belongs to whoever moves fastest.
        </h2>
      </div>
    </section>
  )
}

const REVIEWS = [
  { quote: "Compiled a daemon mid-run and walked straight through the ICE. Nothing else comes close.", handle: "@v_nightcity", role: "Netrunner", glow: "primary" },
  { quote: "The trace monitor saved my deck twice this week. I don't run without it now.", handle: "@rogue_amend", role: "Solo", glow: "accent" },
  { quote: "Latency dropped to nothing. It feels like the grid reads my mind.", handle: "@t_bug", role: "Techie", glow: "primary" },
  { quote: "Set up a private mesh in four minutes. My whole crew is on it.", handle: "@panam_p", role: "Fixer", glow: "accent" },
]

/**
 * Cyber testimonials — glowing slate review cards with mono handles.
 */
export function TestimonialsCyber() {
  return (
    <section className="border-b border-primary/20 bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-6xl">
        <p className="font-mono text-[11px] tracking-[0.3em] uppercase text-primary">// runner_logs</p>
        <h2 className="mt-4 text-[clamp(2rem,5vw,3.25rem)] font-black tracking-tight">Word from the grid</h2>

        <div className="mt-10 grid gap-5 sm:grid-cols-2 lg:grid-cols-4">
          {REVIEWS.map((r) => (
            <figure
              key={r.handle}
              className={`flex flex-col justify-between border bg-card p-6 ${r.glow === "accent" ? "border-accent/40" : "border-primary/40"}`}
            >
              <blockquote className="text-base leading-snug">&ldquo;{r.quote}&rdquo;</blockquote>
              <figcaption className="mt-5">
                <span className={`block font-mono text-sm font-bold ${r.glow === "accent" ? "text-accent" : "text-primary"}`}>
                  {r.handle}
                </span>
                <span className="font-mono text-[11px] tracking-[0.15em] uppercase text-muted-foreground">{r.role}</span>
              </figcaption>
            </figure>
          ))}
        </div>
      </div>
    </section>
  )
}

import { Check } from "lucide-react"

const PLANS = [
  {
    name: "Street",
    price: "0",
    blurb: "For runners getting wired.",
    points: ["2 cores", "Public mesh", "Community ICE", "Rate-limited"],
    featured: false,
  },
  {
    name: "Runner",
    price: "49",
    blurb: "For solos on the clock.",
    points: ["16 cores", "Private mesh", "ICE-breaker v3", "Live trace monitor", "Priority routing"],
    featured: true,
  },
  {
    name: "Corp",
    price: "199",
    blurb: "For crews running the grid.",
    points: ["Unlimited cores", "Dedicated nodes", "Custom daemons", "SLA + on-call fixer"],
    featured: false,
  },
]

/**
 * Cyber pricing — slate plan cards; the featured one glows cyan.
 */
export function PricingCyber() {
  return (
    <section className="border-b border-primary/20 bg-background px-5 py-16 text-foreground sm:px-8 sm:py-24">
      <div className="mx-auto max-w-6xl">
        <h2 className="text-center text-[clamp(2rem,5vw,3.5rem)] font-black tracking-tight">// select_tier</h2>

        <div className="mt-12 grid items-start gap-6 md:grid-cols-3">
          {PLANS.map((p) => (
            <div
              key={p.name}
              className={`flex flex-col border bg-card p-6 ${
                p.featured
                  ? "border-primary shadow-[0_0_32px_rgba(34,211,238,0.25)] md:-translate-y-3"
                  : "border-border"
              }`}
            >
              <div className="flex items-center justify-between">
                <p className="font-mono text-lg font-black tracking-[0.1em] uppercase">{p.name}</p>
                {p.featured && (
                  <span className="border border-accent/50 px-2 py-0.5 font-mono text-[10px] tracking-[0.2em] uppercase text-accent">
                    popular
                  </span>
                )}
              </div>
              <p className="mt-1.5 text-sm text-muted-foreground">{p.blurb}</p>
              <p className="mt-5 font-mono text-5xl font-black tracking-tight">
                <span className="text-primary">${p.price}</span>
                <span className="text-base text-muted-foreground">/mo</span>
              </p>
              <ul className="mt-6 flex-1 space-y-2.5">
                {p.points.map((pt) => (
                  <li key={pt} className="flex items-center gap-2.5 text-sm">
                    <Check className="size-4 shrink-0 text-primary" />
                    {pt}
                  </li>
                ))}
              </ul>
              <button
                className={`mt-6 border py-3 font-mono text-sm tracking-[0.15em] uppercase transition-all ${
                  p.featured
                    ? "border-primary bg-primary text-primary-foreground hover:shadow-[0_0_20px_rgba(34,211,238,0.6)]"
                    : "border-primary/40 text-primary hover:bg-primary/10"
                }`}
              >
                Jack in
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
